import{_ as r,o as e,c as t,a5 as o}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"Clarke & Park 坐标变换仿真 — abc → αβ → dq","description":"","frontmatter":{"title":"Clarke & Park 坐标变换仿真 — abc → αβ → dq","date":"2026-07-01T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/ClarkeParkSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/ClarkeParkSim.vue","chapterTitle":"仿真专题","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/ClarkeParkSim.md","filePath":"content/motor/simulations/ClarkeParkSim.md","lastUpdated":1782999393000}'),c={name:"content/motor/simulations/ClarkeParkSim.md"};function l(i,a,u,k,s,n){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="clarke-park-坐标变换仿真-—-abc-→-αβ-→-dq" tabindex="-1">Clarke &amp; Park 坐标变换仿真 — abc → αβ → dq <a class="header-anchor" href="#clarke-park-坐标变换仿真-—-abc-→-αβ-→-dq" aria-label="Permalink to &quot;Clarke &amp; Park 坐标变换仿真 — abc → αβ → dq&quot;">​</a></h1><h4 id="clarke-park-坐标变换仿真-—-abc-→-αβ-→-dq-1" tabindex="-1">Clarke &amp; Park 坐标变换仿真 — abc → αβ → dq <a class="header-anchor" href="#clarke-park-坐标变换仿真-—-abc-→-αβ-→-dq-1" aria-label="Permalink to &quot;Clarke &amp; Park 坐标变换仿真 — abc → αβ → dq&quot;">​</a></h4><h2 id="clarke-park-坐标变换原理" tabindex="-1">Clarke &amp; Park 坐标变换原理 <a class="header-anchor" href="#clarke-park-坐标变换原理" aria-label="Permalink to &quot;Clarke &amp; Park 坐标变换原理&quot;">​</a></h2><p>**Clarke 变换 (abc → αβ)：**完整形式为 uα = k(ua-0.5ub-0.5uc), uβ = k(√3/2·ub-√3/2·uc)。三相平衡且无零序时 ua+ub+uc=0，幅值不变型可化简为 uα=ua, uβ=(ua+2ub)/√3。</p><p>**幅值不变 vs 功率不变：**幅值不变型保持空间矢量幅值等于相量峰值，便于 SVPWM/电压限幅理解；功率不变型使用 k=√(2/3)，满足 ua²+ub²+uc² = uα²+uβ²，更适合能量、功率和控制理论推导。两者数值不同，不能混着调 PI 参数。</p><p>**Park 变换 (αβ → dq)：**将静止 αβ 坐标系旋转电角度 θe。公式：ud = uα·cosθ + uβ·sinθ, uq = -uα·sinθ + uβ·cosθ。若 d 轴对准当前矢量，ud 表示同轴/励磁分量，uq 表示正交/转矩分量。</p><p>**工程含义与误区：**dq 直流化让 PI 控制成为可能，但前提是角度 θe 正确、零序假设成立、Clarke/Park 缩放一致。常见错误包括电角度/机械角混用、相序反了导致 uq 符号反、幅值不变和功率不变公式混用。</p>',7)])])}const p=r(c,[["render",l]]);export{m as __pageData,p as default};
